sql:
SELECT u.user_name, cr.redemption_id, cr.coupon_id, cr.redemption_date, cr.order_id, cr.quantity, cr.total_discount_amount
FROM users u
JOIN coupon_redemptions cr ON u.user_id = cr.user_id;

SELECT coupon_name 
FROM coupons 
WHERE coupon_id IN (
    SELECT DISTINCT coupon_id 
    FROM coupon_redemptions
);

SELECT coupon_name, COUNT(*)
FROM coupons
GROUP BY coupon_name;

SELECT coupon_id, MAX(total_discount_amount) AS highest_discount_amount
FROM coupon_redemptions
GROUP BY coupon_id;

SELECT COUNT(*) AS NumberOfInactiveCoupons
FROM coupons
WHERE status = 'inactive';

SELECT * 
FROM coupons 
WHERE status != 'active';

SELECT user_name
FROM users
WHERE user_id IN (
  SELECT user_id
  FROM coupon_redemptions
) AND NOT EXISTS (
  SELECT 1
  FROM orders
  WHERE orders.user_id = users.user_id
);

external_knowledge:
- "coupons" refers to promotional offers used by customers;
- "total revenue" is the sum of the total amounts from orders that used these coupons;
- "past month" means the period from now back 30 days.
